import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API மற்றும் Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/random-image-api-and-public-gallery.md","filePath":"ta/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"ta/Other/random-image-api-and-public-gallery.md"};function o(l,e,s,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-மற்றும்-public-gallery" tabindex="-1">Random Image API மற்றும் Public Gallery <a class="header-anchor" href="#random-image-api-மற்றும்-public-gallery" aria-label="Permalink to &quot;Random Image API மற்றும் Public Gallery&quot;">​</a></h1><p>இரண்டு features-மும் இங்கு configure செய்யப்படுகின்றன:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API selected directories-இல் இருந்து ஒரு random file திரும்ப தரும். site backgrounds, avatar rotation, external pages-இல் random image calls போன்றவற்றுக்கு useful.</p><p>enable செய்த பிறகு:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint on/off. disabled என்றால் access forbidden.</td></tr><tr><td>Directories</td><td>random API பயன்படுத்தக்கூடிய directories limit. இங்கு இல்லாத directories API-க்கு கிடையாது.</td></tr><tr><td>Call demo</td><td>copy செய்யக்கூடிய random API links generate.</td></tr></tbody></table><p>multiple directories தேர்வு செய்யலாம். உதாரணமாக <code>/landscape/</code> மற்றும் <code>/portrait/</code> மட்டும் allowed என்றால் random API அந்த directories மற்றும் subdirectories-இல் இருந்து மட்டும் files pick செய்யும்.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>random directory specify.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>media type. <code>image</code>, <code>video</code>, <code>audio</code>, அல்லது comma-separated combinations.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>image orientation filter. <code>portrait</code>, <code>landscape</code>, அல்லது <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>return format. empty என்றால் redirect, <code>url</code> text URL, <code>json</code> JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> உடன் full URL return.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>age rating filter.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>இந்த tags உள்ள files மட்டும் return.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>இந்த tags உள்ள files exclude.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p><code>type</code> இல்லாமல் API random file URL-க்கு direct redirect செய்கிறது.</p><p><code>type=url</code> என்றால் text URL தரும்.</p><p><code>type=json</code> என்றால் file URL, file ID, file name, file type, tags, rating, related metadata உடன் file information தரும்.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API public access rules follow செய்கிறது:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>allowed directories உள்ள files மட்டும் தேர்வு.</td></tr><tr><td>Blocklist</td><td>blocklisted files random pool-ல் இருந்து exclude.</td></tr><tr><td>Allowlist mode</td><td>enabled என்றால் public access allowed files மட்டும் return.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 போன்ற content current access mode படி filter.</td></tr></tbody></table><p>filter பிறகு matching file இல்லை என்றால் API no matching result தரும்.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API speed மேம்பட directory candidate pools cache செய்கிறது.</p><p>files மாறிய பிறகு ImgBed directory cache version update செய்கிறது; பின்னர் requests candidate pool மீண்டும் build செய்யும். empty directories repeated queries தவிர்க்க குறுகிய நேரம் cache செய்யப்படும்.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery visitors பார்க்க அனுமதிக்கும் directories-க்கு read-only public browsing page தரும்.</p><p>enable செய்த பிறகு visitors திறக்கலாம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>public gallery on/off. disabled என்றால் visitors browse செய்ய முடியாது.</td></tr><tr><td>Image loading mode</td><td>previews original images அல்லது thumbnails பயன்படுத்துமா என்பதை கட்டுப்படுத்தும்.</td></tr><tr><td>Open directories</td><td>visitors access செய்யக்கூடிய directories.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>visitor page original files நேரடியாக load செய்யும்.</td></tr><tr><td>Thumbnail</td><td>faster loading-க்கு thumbnails முன்னுரிமை.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories visitors என்ன பார்க்கலாம் என்பதை முடிவு செய்கிறது.</p><p>உதாரணம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors access செய்யலாம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories-யும் open செய்யலாம், உதா. <code>/2026/lucky/</code>. open செய்யாத directories-க்கு visitors blocked.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>open directories-ல் files மற்றும் subdirectories பார்க்க.</td></tr><tr><td>Search</td><td>file name, file ID, tags மூலம் search.</td></tr><tr><td>Type filter</td><td>images, videos, audio, other files filter.</td></tr><tr><td>Tag filter</td><td>selected tags include/exclude.</td></tr><tr><td>Orientation filter</td><td>landscape அல்லது portrait images filter.</td></tr><tr><td>Time filter</td><td>upload time range filter.</td></tr><tr><td>Extension filter</td><td>file extension filter.</td></tr><tr><td>Copy link</td><td>file access links copy.</td></tr><tr><td>Media preview</td><td>visitor page-ல் images, videos, audio பார்க்க/play.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery-யும் public access rules follow செய்கிறது:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>allowed directories மட்டும் காட்டப்படும்.</td></tr><tr><td>Access mode</td><td>current age-rating access mode படி content filter.</td></tr><tr><td>Allowlist mode</td><td>enabled என்றால் public access allowed files மட்டும் காட்டப்படும்.</td></tr><tr><td>Blocklist</td><td>blocklisted files hidden.</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
